function expandMrKowalski(node) {
  if (Array.isArray(node)) return node.map(expandMrKowalski);
  if (node && typeof node === "object") {
    const out = {};
    for (const [k, v] of Object.entries(node)) {
      if (k === "mr_kowalski" && (typeof v === "string" || v === null)) {
        out[k] = "John Ronald Kowalski";
      } else {
        out[k] = expandMrKowalski(v);
      }
    }
    return out;
  }
  return node;
}

